fn babel_int_emit_str(off: u32, src: u64, len: u32) -> u32 {
    let mut i : u32 = 0u32
    while i < len {
        let bp : *u8 = (src + ((i as u64) & 0xFFFFu64)) as *u8
        babel_int_emit(off + i, bp[0u64])
        i = i + 1u32
    }
    return len
