fn babel_int_emit_dec(off: u32, v: u64) -> u32 {
    if v == 0u64 {
        babel_int_emit(off, 48u8)
        return 1u32
    }
    let mut n : u32 = 0u32
    let mut x : u64 = v
    while x != 0u64 {
        BABEL_INTENT_DIGITS[n] = ((x % 10u64) & 0xFFu64) as u8 + 48u8
        x = x / 10u64
        n = n + 1u32
    }
    let total : u32 = n
    let mut written : u32 = 0u32
    while n != 0u32 {
        n = n - 1u32
        babel_int_emit(off + written, BABEL_INTENT_DIGITS[n])
        written = written + 1u32
    }
    return total
}

