fn babel_intent_send(intent_ptr: u64, crystal_id: u64, dst_buf: u64, dst_cap: u32) -> u32 @export {
    if intent_ptr == 0u64 { return 0u32 }
    let mut off : u32 = 0u32
    /* Prefix */
    off = off + babel_int_emit_str(off, (&BABEL_PRE) as u64, 47u32)
    off = off + babel_int_emit_hex16(off, crystal_id)
    /* Suffix 1 */
    off = off + babel_int_emit_str(off, (&BABEL_SFX1) as u64, 14u32)
    babel_int_emit(off, 34u8); off = off + 1u32
    off = off + babel_int_emit_dec(off, intent_goal_kind(intent_ptr) as u64)
    babel_int_emit(off, 34u8); off = off + 1u32
    /* Suffix 2 */
    off = off + babel_int_emit_str(off, (&BABEL_SFX2) as u64, 13u32)
    babel_int_emit(off, 34u8); off = off + 1u32
    off = off + babel_int_emit_hex16(off, intent_id(intent_ptr))
    babel_int_emit(off, 34u8); off = off + 1u32
    /* Suffix 3 */
    off = off + babel_int_emit_str(off, (&BABEL_SFX3) as u64, 23u32)
    babel_int_emit(off, 34u8); off = off + 1u32
    off = off + babel_int_emit_dec(off, intent_required_guarantees(intent_ptr) as u64 & 0xFFFFFFFFu64)
    babel_int_emit(off, 34u8); off = off + 1u32
    /* Suffix 4 */
    off = off + babel_int_emit_str(off, (&BABEL_SFX4) as u64, 18u32)
    babel_int_emit(off, 34u8); off = off + 1u32
    off = off + babel_int_emit_dec(off, intent_expected_hexad_kind(intent_ptr) as u64)
    babel_int_emit(off, 34u8); off = off + 1u32
    /* Closing */
    babel_int_emit(off, 125u8); off = off + 1u32
    /* Copy result to dst_buf */
    if (off as u32) > dst_cap { return 0u32 }
    let mut k : u32 = 0u32
    while k < off {
        let dp : *u8 = (dst_buf + ((k as u64) & 0xFFFu64)) as *u8
        dp[0u64] = BABEL_INTENT_OUT_BUF[k]
        k = k + 1u32
    }
    return off
}

